import pytest
from your_module import zip_dicts  # Replace 'your_module' with the actual module name

def test_happy_path():
    """Test basic functionality with multiple dictionaries."""
    dict1 = {'a': 1, 'b': 2}
    dict2 = {'a': 3, 'c': 4}
    dict3 = {'b': 5, 'd': 6}

    result = zip_dicts(dict1, dict2, dict3)
    expected = {
        'a': [1, 3, None],
        'b': [2, None, 5],
        'c': [None, 4, None],
        'd': [None, None, 6]
    }
    assert result == expected

def test_empty_dicts():
    """Test with empty dictionaries."""
    result = zip_dicts({}, {}, {})
    assert result == {}

def test_single_dict():
    """Test with a single dictionary."""
    dict1 = {'a': 1, 'b': 2}
    result = zip_dicts(dict1)
    expected = {'a': [1], 'b': [2]}
    assert result == expected

def test_no_dicts():
    """Test with no dictionaries provided."""
    result = zip_dicts()
    assert result == {}

def test_duplicate_keys():
    """Test with dictionaries containing duplicate keys."""
    dict1 = {'a': 1, 'b': 2}
    dict2 = {'a': 3, 'b': 4}
    result = zip_dicts(dict1, dict2)
    expected = {'a': [1, 3], 'b': [2, 4]}
    assert result == expected

def test_none_values():
    """Test with None values in dictionaries."""
    dict1 = {'a': None, 'b': 2}
    dict2 = {'a': 3, 'c': None}
    result = zip_dicts(dict1, dict2)
    expected = {'a': [None, 3], 'b': [2, None], 'c': [None, None]}
    assert result == expected

def test_mixed_types():
    """Test with mixed value types in dictionaries."""
    dict1 = {'a': 1, 'b': 'hello'}
    dict2 = {'a': [1, 2], 'c': {'nested': 'dict'}}
    result = zip_dicts(dict1, dict2)
    expected = {
        'a': [1, [1, 2]],
        'b': ['hello', None],
        'c': [None, {'nested': 'dict'}]
    }
    assert result == expected

def test_non_dict_input():
    """Test with non-dictionary inputs (should raise TypeError)."""
    with pytest.raises(TypeError):
        zip_dicts({'a': 1}, "not a dict", {'b': 2})

def test_dict_like_objects():
    """Test with dictionary-like objects that have .keys() method."""
    class DictLike:
        def __init__(self, data):
            self.data = data

        def keys(self):
            return self.data.keys()

        def get(self, key):
            return self.data.get(key)

    dict1 = DictLike({'a': 1, 'b': 2})
    dict2 = DictLike({'a': 3, 'c': 4})

    result = zip_dicts(dict1, dict2)
    expected = {'a': [1, 3], 'b': [2, None], 'c': [None, 4]}
    assert result == expected

def test_large_number_of_dicts():
    """Test with a large number of dictionaries."""
    dicts = [{f'key{i}': i for i in range(10)} for _ in range(100)]
    result = zip_dicts(*dicts)

    # Verify structure is correct
    assert len(result) == 10
    for key, values in result.items():
        assert len(values) == 100
        # The first dict has all keys, others have None for missing keys
        assert values[0] == int(key[3:])  # key is 'keyX' where X is the number
